#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// ============================================
// Basic Structure Definition
// ============================================
struct Student {
 int roll_no;
 char name[50];
 float marks;
};

// Nested structure
struct Date {
 int day;
 int month;
 int year;
};

struct Employee {
 int emp_id;
 char name[50];
 struct Date join_date;
};

// Self-referential structure for linked list
struct Node {
 int data;
 struct Node* next;
};

// Tree node structure
struct TreeNode {
 int data;
 struct TreeNode* left;
 struct TreeNode* right;
};

// ============================================
// Function to create and initialize a student (factory pattern)
// ============================================
struct Student* createStudent(int roll, const char* name, float marks) {
 struct Student* s = (struct Student*)malloc(sizeof(struct Student));
 if (s == NULL) {
 printf("Memory allocation failed!\n");
 return NULL;
 }
 s->roll_no = roll;
 strncpy(s->name, name, 49);
 s->name[49] = '\0';
 s->marks = marks;
 return s;
}

// ============================================
// Function to create linked list node
// ============================================
struct Node* createNode(int value) {
 struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
 newNode->data = value;
 newNode->next = NULL; // Always initialize pointers!
 return newNode;
}

// ============================================
// Function to create tree node
// ============================================
struct TreeNode* createTreeNode(int value) {
 struct TreeNode* node = (struct TreeNode*)malloc(sizeof(struct TreeNode));
 node->data = value;
 node->left = NULL;
 node->right = NULL;
 return node;
}

// ============================================
// Print student details
// ============================================
void printStudent(struct Student s) {
 printf("Roll No: %d, Name: %s, Marks: %.2f\n", s.roll_no, s.name, s.marks);
}

void printEmployee(struct Employee e) {
 printf("Employee ID: %d, Name: %s, Join Date: %d/%d/%d\n",
 e.emp_id, e.name, e.join_date.day, e.join_date.month, e.join_date.year);
}

// ============================================
// Main function demonstrating all methods
// ============================================
int main() {
 printf("=== C Structure Initialization Demo ===\n\n");

 // Method 1: Initialization at declaration (in order)
 printf("Method 1: Direct initialization at declaration\n");
 struct Student s1 = {101, "Alice", 85.5};
 printStudent(s1);

 // Method 2: Designated initializers (C99)
 printf("\nMethod 2: Designated initializers (C99)\n");
 struct Student s2 = {
 .roll_no = 102,
 .name = "Bob",
 .marks = 78.3
 };
 printStudent(s2);

 // Method 3: Partial initialization (remaining = 0)
 printf("\nMethod 3: Partial initialization\n");
 struct Student s3 = {103}; // Only roll_no=103, others=0
 printStudent(s3);

 // Method 4: Zero initialization
 printf("\nMethod 4: Zero initialization\n");
 struct Student s4 = {0}; // All members = 0
 printStudent(s4);

 // Method 5: Using typedef (optional)
 printf("\nMethod 5: Using typedef\n");
 typedef struct {
 int x;
 int y;
 } Point;
 Point p1 = {10, 20}; // No 'struct' keyword needed
 printf("Point: x=%d, y=%d\n", p1.x, p1.y);

 // Method 6: Nested structure initialization
 printf("\nMethod 6: Nested structure initialization\n");
 struct Employee emp1 = {1001, "John Smith", {15, 6, 2020}};
 printEmployee(emp1);

 // Nested with designated initializers
 struct Employee emp2 = {
 .emp_id = 1002,
 .name = "Jane Doe",
 .join_date = {.day = 20, .month = 8, .year = 2021}
 };
 printEmployee(emp2);

 // Method 7: Array of structures
 printf("\nMethod 7: Array of structures\n");
 struct Student students[3] = {
 {201, "Mike", 90.0},
 {202, "Sarah", 88.5},
 {203, "Tom", 75.2}
 };
 for (int i = 0; i < 3; i++) {
 printf(" Student %d: ", i+1);
 printStudent(students[i]);
 }

 // Method 8: Self-referential structure (Linked List)
 printf("\nMethod 8: Self-referential (Linked List)\n");
 struct Node* head = createNode(10);
 head->next = createNode(20);
 head->next->next = createNode(30);

 struct Node* temp = head;
 printf("Linked List: ");
 while (temp != NULL) {
 printf("%d ", temp->data);
 temp = temp->next;
 }
 printf("\n");

 // Method 9: Compound literal (C99)
 printf("\nMethod 9: Compound literal (C99)\n");
 struct Student* s5 = &((struct Student){105, "compound literal", 95.0});
 printStudent(*s5);

 // Method 10: Using factory function
 printf("\nMethod 10: Factory function initialization\n");
 struct Student* s6 = createStudent(106, "Factory Created", 82.5);
 printStudent(*s6);

 // Tree structure example
 printf("\nMethod 11: Tree node initialization\n");
 struct TreeNode* root = createTreeNode(50);
 root->left = createTreeNode(30);
 root->right = createTreeNode(70);
 printf("Tree root: %d, Left: %d, Right: %d\n", 
 root->data, root->left->data, root->right->data);

 // ============================================
 // Free allocated memory
 // ============================================
 temp = head;
 while (temp != NULL) {
 struct Node* next = temp->next;
 free(temp);
 temp = next;
 }

 // Free tree nodes
 free(root->left);
 free(root->right);
 free(root);

 free(s6);

 printf("\n=== Demo Complete ===\n");
 return 0;
}
